/**
 * useAdmin Custom Hook
 *
 * adminApi の全メソッドをラップするカスタムフック。
 * admin pages が adminApi を直接 import せずに管理機能を使用できる。
 */

import { adminApi } from '../services/adminApi';

export interface UseAdminReturn {
  listUsers: typeof adminApi.listUsers;
  createUser: typeof adminApi.createUser;
  getUser: typeof adminApi.getUser;
  deleteUser: typeof adminApi.deleteUser;
  enableUser: typeof adminApi.enableUser;
  disableUser: typeof adminApi.disableUser;
  resetPassword: typeof adminApi.resetPassword;
  promoteToAdmin: typeof adminApi.promoteToAdmin;
  getAuditLogs: typeof adminApi.getAuditLogs;
}

export const useAdmin = (): UseAdminReturn => {
  return adminApi;
};
