/**
 * Admin API Client Service
 *
 * Provides type-safe API calls for admin user management operations.
 * All endpoints require admin authentication (Admins group membership).
 */

import { AxiosError } from 'axios';
import type {
  AdminUserDto,
  CreateUserRequestDto,
  CreateUserResponseDto,
  ListUsersResponseDto,
  ResetPasswordResponseDto,
  AuditLogEntryDto,
} from 'shared';
import { apiClient } from './apiClient';

/**
 * Admin API client
 * All methods require admin privileges
 */
export const adminApi = {
  /**
   * GET /api/admin/users
   * List users with pagination and optional search
   */
  async listUsers(params?: {
    limit?: number;
    paginationToken?: string;
    search?: string;
  }): Promise<ListUsersResponseDto> {
    try {
      const response = await apiClient.get('/admin/users', { params });
      return response.data;
    } catch (error) {
      throw handleApiError(error);
    }
  },

  /**
   * POST /api/admin/users
   * Create a new user
   */
  async createUser(data: CreateUserRequestDto): Promise<CreateUserResponseDto> {
    try {
      const response = await apiClient.post('/admin/users', data);
      return response.data;
    } catch (error) {
      throw handleApiError(error);
    }
  },

  /**
   * GET /api/admin/users/:userId
   * Get user details
   */
  async getUser(userId: string): Promise<AdminUserDto> {
    try {
      const response = await apiClient.get(`/admin/users/${userId}`);
      return response.data;
    } catch (error) {
      throw handleApiError(error);
    }
  },

  /**
   * DELETE /api/admin/users/:userId
   * Delete user
   */
  async deleteUser(userId: string): Promise<{ message: string }> {
    try {
      const response = await apiClient.delete(`/admin/users/${userId}`);
      return response.data;
    } catch (error) {
      throw handleApiError(error);
    }
  },

  /**
   * POST /api/admin/users/:userId/enable
   * Enable disabled user
   */
  async enableUser(userId: string): Promise<{ message: string }> {
    try {
      const response = await apiClient.post(`/admin/users/${userId}/enable`, {});
      return response.data;
    } catch (error) {
      throw handleApiError(error);
    }
  },

  /**
   * POST /api/admin/users/:userId/disable
   * Disable active user
   */
  async disableUser(userId: string): Promise<{ message: string }> {
    try {
      const response = await apiClient.post(`/admin/users/${userId}/disable`, {});
      return response.data;
    } catch (error) {
      throw handleApiError(error);
    }
  },

  /**
   * POST /api/admin/users/:userId/reset-password
   * Reset user password
   */
  async resetPassword(userId: string): Promise<ResetPasswordResponseDto> {
    try {
      const response = await apiClient.post(`/admin/users/${userId}/reset-password`, {});
      return response.data;
    } catch (error) {
      throw handleApiError(error);
    }
  },

  /**
   * POST /api/admin/users/:userId/promote-to-admin
   * Promote user to admin
   */
  async promoteToAdmin(userId: string): Promise<{ message: string }> {
    try {
      const response = await apiClient.post(`/admin/users/${userId}/promote-to-admin`, {});
      return response.data;
    } catch (error) {
      throw handleApiError(error);
    }
  },

  /**
   * GET /api/admin/audit-logs
   * Get audit logs with optional filters
   */
  async getAuditLogs(params?: {
    limit?: number;
    operation?: string;
    adminEmail?: string;
    startTime?: string;
    endTime?: string;
  }): Promise<{ logs: AuditLogEntryDto[] }> {
    try {
      const response = await apiClient.get('/admin/audit-logs', { params });
      return response.data;
    } catch (error) {
      throw handleApiError(error);
    }
  },
};

/**
 * Handle API errors and extract meaningful error messages
 */
function handleApiError(error: unknown): Error {
  if (error instanceof AxiosError) {
    const axiosError = error as AxiosError<{ error?: string; message?: string }>;
    const message =
      axiosError.response?.data?.message ||
      axiosError.response?.data?.error ||
      axiosError.message ||
      'An error occurred';
    return new Error(message);
  }
  return error instanceof Error ? error : new Error('Unknown error');
}
